class Solution {
public:
    int minSubArrayLen(int target, vector<int>& nums) {

        int l = 0, r = 0;
        int n = nums.size()-1;

        int result = INT_MAX;
        int slide_value = nums[0];
        while(r < n || l < n){
            if(slide_value >= target){
                result = min(r-l +1, result);
                if(result == 0)
                    return result;
                slide_value -= nums[l];
                l++;
            } else {
                if(r < n){
                    r++;
                    slide_value += nums[r];
                }
                else{
                    break;
                }
            }

        }
        if(result == INT_MAX)
            return 0;
        return result;

    }
};

