        int n = nums.size()-1;

        if(n == 0){
            return static_cast<int>(nums[0] >= target);
        }

        int result = INT_MAX;
        int slide_value = nums[0];
        while(r < n || l < n){
            if(slide_value >= target){
                result = min(r-l +1, result);
                if(result == 0)
                    return result;
